&lt;p&gt;Quel est le problème avec cette mise à jour d'un tableau d'objets ?&lt;/p&gt;&lt;pre&gt;&lt;code&gt;const [todos, setTodos] = useState([
  { id: 1, text: "Apprendre React", done: false }
]);

function toggleTodo(id) {
  const todo = todos.find(t =&gt; t.id === id);
  todo.done = !todo.done;
  setTodos(todos);
}&lt;/code&gt;&lt;/pre&gt;
